encountered ← empty_set
for each step s in trajectory T_G over window w:
    for each fragment m in ℱ(M):
        if s is contained in m:
            encountered ← encountered ∪ {m}
            break
C_est ← |encountered| / |ℱ(M)|
return encountered, C_est

// observer-class; no state mutation
C <- estimate_coherence_density(motif_fragments, window=alignment_window)
delta <- N_p - C
if delta > 0:
    // Test torsion residuals across fragment triads
    for each triad (f_i, f_j, f_k) in motif_fragments:
        torsion <- estimate_torsion_residual(f_i, f_j, f_k)
        if torsion > torsion_threshold:
            advisories.append("persistent_torsion:" + triad_hash)
    // Classification decision
    if C > N_p * 0.7:
        classification = "latent"  // approaching threshold
    else:
        classification = "noise"    // deep in sub-threshold
else:
    classification = "detectable"   // handled in §3.3
return classification, delta, advisories

aligned <- 0
total <- len(fragments)
for i in range(total):
    for j in range(i+1, total):
        if binary_alignment(fragments[i], fragments[j]) > threshold:
            aligned++
return aligned / (total * (total-1) / 2)  // pairwise alignment fraction

bias ← zero_vector
for each fragment m in encountered_fragments:
    # Find centroid of remaining unexplored regions of m
    centroid ← fragment_map.centroid(m, exclude_visited=TRUE)
    direction ← centroid - x
    if ||direction|| <= influence_radius:
        weight ← 1.0 if weighting=='uniform' else C(centroid)
        bias ← bias + weight * normalize(direction)
return normalize(bias + ε)

for t in time_series:
    if C(M,t) >= N_p and (t == 0 or C(M,t-1) < N_p):
        return t, True
return None, False

# Phase 1: Detect threshold crossing
t_trigger = None
for t in [t0 ... t1]:
  C_smooth = EMA(C(t), smoothing_window)
  if C_smooth >= N_p and t_trigger is None:
    t_trigger = t
    break

if t_trigger is None:
  return {cascade_active: false}

# Phase 2: Identify first detector
G_first = None
t_first = infinity
detection_times = {}

for G_i in explorers:
  # Find when this explorer's trajectory first encounters M after threshold
  encounter_time = first_encounter_after(T_Gi, M, t_trigger)
  if encounter_time is not None:
    detection_times[G_i] = encounter_time
    if encounter_time < t_first:
      t_first = encounter_time
      G_first = G_i

# Phase 3: Cascade propagation
cascade_active = (len(detection_times) > 0)

return {
  trigger_time: t_trigger,
  first_detector: G_first,
  detection_times: detection_times,
  cascade_active: cascade_active,
  cascade_magnitude: len(detection_times)
}

best_form ← null
best_coherence ← -∞
for a in motif_candidates:
    canon_coherence ← sum([C(a ∧ M_j) for M_j in existing_canon])
    if canon_coherence ≥ threshold_C_stab and canon_coherence > best_coherence:
        best_coherence ← canon_coherence
        best_form ← a
if best_form is not null:
    # verify mutual coherence with canon
    mutual_coherence ← min([C(best_form ∧ M_j) - C(best_form)*C(M_j) for M_j in existing_canon])
    if mutual_coherence > threshold_δ:
        updated_canon ← existing_canon ∪ {best_form}
        return best_form, updated_canon
return null, existing_canon
